import{_ as a,o as n,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Homebrew Distribution","description":"Create and maintain a Homebrew tap that lets macOS and Linux users install your agent with a single brew install command.","frontmatter":{"title":"Homebrew Distribution","description":"Create and maintain a Homebrew tap that lets macOS and Linux users install your agent with a single brew install command."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/05-homebrew-distribution.md","filePath":"learn/linear/17-packaging-and-distribution/05-homebrew-distribution.md"}'),e={name:"learn/linear/17-packaging-and-distribution/05-homebrew-distribution.md"};function t(p,s,r,c,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="homebrew-distribution" tabindex="-1">Homebrew Distribution <a class="header-anchor" href="#homebrew-distribution" aria-label="Permalink to &quot;Homebrew Distribution&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to create a Homebrew formula that downloads prebuilt binaries and installs them with proper shell completions and man pages</li><li>Techniques for setting up a Homebrew tap repository with automated formula updates triggered by new GitHub releases</li><li>How to handle Homebrew-specific requirements including bottle generation, dependency declarations, and version pinning</li></ul></blockquote><p>Homebrew is the dominant package manager on macOS and has strong adoption on Linux as well. For CLI tools targeting developers, <code>brew install</code> is the gold standard of distribution. A single command downloads, installs, and configures your agent with shell completions and proper PATH setup. This subchapter walks through creating a Homebrew formula from scratch and automating updates as you release new versions.</p><h2 id="how-homebrew-works" tabindex="-1">How Homebrew Works <a class="header-anchor" href="#how-homebrew-works" aria-label="Permalink to &quot;How Homebrew Works&quot;">​</a></h2><p>Homebrew installs software into its own prefix (<code>/opt/homebrew</code> on Apple Silicon, <code>/usr/local</code> on Intel Mac, <code>/home/linuxbrew/.linuxbrew</code> on Linux) and symlinks binaries into a directory on the user&#39;s PATH. A <strong>formula</strong> is a Ruby script that tells Homebrew how to download, build (or just unpack), and install your software.</p><p>There are two ways to distribute through Homebrew:</p><ol><li><strong>Homebrew core</strong> -- Submit your formula to the official <code>homebrew/homebrew-core</code> repository. This requires meeting strict criteria (notable project, active maintenance, no unnecessary dependencies) and going through a review process.</li><li><strong>Custom tap</strong> -- Host your own formula repository. Users install with <code>brew tap yourname/tap &amp;&amp; brew install my-agent</code> or <code>brew install yourname/tap/my-agent</code>. This is the practical choice for most projects.</li></ol><p>We will focus on the custom tap approach because you control the entire pipeline and can start distributing immediately.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Homebrew can install Python tools too -- many CLI tools distributed through <code>pip</code> also have Homebrew formulas. But Homebrew formulas for Python tools are complex: they need to declare Python as a dependency, manage virtual environments, and handle Python version upgrades. Rust binaries are radically simpler: the formula downloads a prebuilt binary and copies it into place. No interpreter, no virtual environment, no dependency isolation.</p></div><h2 id="creating-a-homebrew-tap" tabindex="-1">Creating a Homebrew Tap <a class="header-anchor" href="#creating-a-homebrew-tap" aria-label="Permalink to &quot;Creating a Homebrew Tap&quot;">​</a></h2><p>A tap is a GitHub repository with a specific naming convention. Create a repository named <code>homebrew-tap</code> (the <code>homebrew-</code> prefix is required):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Create the tap repository on GitHub</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">gh</span><span style="color:#A6E3A1;"> repo</span><span style="color:#A6E3A1;"> create</span><span style="color:#A6E3A1;"> homebrew-tap</span><span style="color:#A6E3A1;"> --public</span><span style="color:#A6E3A1;"> --description</span><span style="color:#A6E3A1;"> &quot;Homebrew formulas&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Clone it</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> clone</span><span style="color:#A6E3A1;"> https://github.com/yourname/homebrew-tap.git</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> homebrew-tap</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Create the Formula directory (required by Homebrew convention)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">mkdir</span><span style="color:#A6E3A1;"> Formula</span></span></code></pre></div><p>The repository structure is:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>homebrew-tap/</span></span>
<span class="line"><span>  Formula/</span></span>
<span class="line"><span>    my-agent.rb    # Your formula file</span></span>
<span class="line"><span>  README.md</span></span></code></pre></div><h2 id="writing-the-formula" tabindex="-1">Writing the Formula <a class="header-anchor" href="#writing-the-formula" aria-label="Permalink to &quot;Writing the Formula&quot;">​</a></h2><p>A formula for prebuilt binaries is straightforward. Create <code>Formula/my-agent.rb</code>:</p><div class="language-ruby"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#FAB387;"> MyAgent</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#FAB387;"> Formula</span></span>
<span class="line"><span style="color:#CDD6F4;">  desc </span><span style="color:#A6E3A1;">&quot;A CLI coding agent powered by large language models&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  homepage </span><span style="color:#A6E3A1;">&quot;https://github.com/yourname/my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  version </span><span style="color:#A6E3A1;">&quot;0.5.2&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  license </span><span style="color:#A6E3A1;">&quot;MIT&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">  on_macos </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">    on_arm </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourname/my-agent/releases/download/v0.5.2/my-agent-aarch64-apple-darwin.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;abc123...full-sha256-hash-here...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CDD6F4;">    on_intel </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourname/my-agent/releases/download/v0.5.2/my-agent-x86_64-apple-darwin.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;def456...full-sha256-hash-here...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">  on_linux </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">    on_arm </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourname/my-agent/releases/download/v0.5.2/my-agent-aarch64-unknown-linux-musl.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;789abc...full-sha256-hash-here...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CDD6F4;">    on_intel </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourname/my-agent/releases/download/v0.5.2/my-agent-x86_64-unknown-linux-musl.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;012def...full-sha256-hash-here...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">  def</span><span style="color:#89B4FA;font-style:italic;"> install</span></span>
<span class="line"><span style="color:#CDD6F4;">    bin</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Install shell completions if included in the archive</span></span>
<span class="line"><span style="color:#CDD6F4;">    bash_completion</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;completions/my-agent.bash&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    zsh_completion</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;completions/_my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    fish_completion</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;completions/my-agent.fish&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Install man page if included</span></span>
<span class="line"><span style="color:#CDD6F4;">    man1</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;man/my-agent.1&quot;</span><span style="color:#CBA6F7;"> if</span><span style="color:#F9E2AF;font-style:italic;"> File</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">exist?</span><span style="color:#A6E3A1;"> &quot;man/my-agent.1&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">  test</span><span style="color:#CBA6F7;"> do</span></span>
<span class="line"><span style="color:#CDD6F4;">    assert_match version</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">to_s</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> shell_output</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">bin</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/my-agent --version&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"><span style="color:#CBA6F7;">end</span></span></code></pre></div><p>Let&#39;s break down the key parts:</p><ul><li><strong><code>on_macos</code> / <code>on_linux</code> / <code>on_arm</code> / <code>on_intel</code></strong> -- Conditional blocks that select the right binary for the user&#39;s platform and architecture. Homebrew evaluates these at install time.</li><li><strong><code>sha256</code></strong> -- A cryptographic hash of each archive. Homebrew verifies this to ensure the download has not been tampered with. Generate it with <code>shasum -a 256 filename.tar.gz</code>.</li><li><strong><code>bin.install</code></strong> -- Copies the binary into the Homebrew bin directory and creates the symlink.</li><li><strong><code>bash_completion.install</code></strong> -- Installs shell completions to the right location so they are automatically loaded.</li><li><strong><code>test</code></strong> -- A simple smoke test that Homebrew runs with <code>brew test my-agent</code>.</li></ul><h2 id="generating-shell-completions" tabindex="-1">Generating Shell Completions <a class="header-anchor" href="#generating-shell-completions" aria-label="Permalink to &quot;Generating Shell Completions&quot;">​</a></h2><p>Most Rust CLI tools use <code>clap</code> for argument parsing. Clap can generate shell completions at build time. Add this to your <code>build.rs</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> clap</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">CommandFactory</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> clap_complete</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">generate_to</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> shells</span><span style="color:#9399B2;">};</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">fs</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Assuming your CLI struct is defined in src/cli.rs</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">include!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;src/cli.rs&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> out_dir </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">path</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">PathBuf</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#F9E2AF;">        std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;CARGO_MANIFEST_DIR&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">    )</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;completions&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;">    fs</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">create_dir_all</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">out_dir</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> cmd </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Cli</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">command</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    generate_to</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">shells</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Bash</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">out_dir</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    generate_to</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">shells</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Zsh</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">out_dir</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    generate_to</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">shells</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Fish</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">out_dir</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Alternatively, many CLI tools generate completions at runtime with a <code>--completions</code> subcommand:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> clap</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> CommandFactory</span><span style="color:#9399B2;">};</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> clap_complete</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">generate</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Shell</span><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> print_completions</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">shell</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Shell</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> cmd </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Cli</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">command</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    generate</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">shell</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;my-agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">io</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">stdout</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Include the generated completion files in your release archive alongside the binary.</p><h2 id="computing-sha256-hashes" tabindex="-1">Computing SHA256 Hashes <a class="header-anchor" href="#computing-sha256-hashes" aria-label="Permalink to &quot;Computing SHA256 Hashes&quot;">​</a></h2><p>When updating the formula, you need the SHA256 hash of each platform&#39;s archive. Compute them from your release artifacts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># After building release archives</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> my-agent-</span><span style="color:#CDD6F4;">*</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">*</span><span style="color:#A6E3A1;">.tar.gz</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Output:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># abc123...  my-agent-aarch64-apple-darwin.tar.gz</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># def456...  my-agent-x86_64-apple-darwin.tar.gz</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># 789abc...  my-agent-aarch64-unknown-linux-musl.tar.gz</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># 012def...  my-agent-x86_64-unknown-linux-musl.tar.gz</span></span></code></pre></div><p>Paste these hashes into the formula. If a hash does not match at install time, Homebrew refuses to install -- this is a critical security feature.</p><h2 id="automating-formula-updates" tabindex="-1">Automating Formula Updates <a class="header-anchor" href="#automating-formula-updates" aria-label="Permalink to &quot;Automating Formula Updates&quot;">​</a></h2><p>Manually updating the formula for every release is tedious and error-prone. Automate it with GitHub Actions. Add this job to your release workflow:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">update-homebrew</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  needs</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">build</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> release</span><span style="color:#9399B2;">]</span><span style="color:#6C7086;font-style:italic;">  # Run after binaries are published</span></span>
<span class="line"><span style="color:#89B4FA;">  runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">  steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Checkout tap repository</span></span>
<span class="line"><span style="color:#89B4FA;">      uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"><span style="color:#89B4FA;">      with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">        repository</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> yourname/homebrew-tap</span></span>
<span class="line"><span style="color:#89B4FA;">        token</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ secrets.TAP_GITHUB_TOKEN }}</span></span>
<span class="line"><span style="color:#89B4FA;">        path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> homebrew-tap</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Download release assets and compute hashes</span></span>
<span class="line"><span style="color:#89B4FA;">      run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">        VERSION=&quot;\${GITHUB_REF_NAME#v}&quot;  # Strip &#39;v&#39; prefix</span></span>
<span class="line"><span style="color:#A6E3A1;">        BASE_URL=&quot;https://github.com/yourname/my-agent/releases/download/\${GITHUB_REF_NAME}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">        declare -A TARGETS=(</span></span>
<span class="line"><span style="color:#A6E3A1;">          [&quot;aarch64-apple-darwin&quot;]=&quot;on_macos.*on_arm&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          [&quot;x86_64-apple-darwin&quot;]=&quot;on_macos.*on_intel&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          [&quot;aarch64-unknown-linux-musl&quot;]=&quot;on_linux.*on_arm&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          [&quot;x86_64-unknown-linux-musl&quot;]=&quot;on_linux.*on_intel&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        )</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">        for target in &quot;\${!TARGETS[@]}&quot;; do</span></span>
<span class="line"><span style="color:#A6E3A1;">          ARCHIVE=&quot;my-agent-\${target}.tar.gz&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          curl -sL &quot;\${BASE_URL}/\${ARCHIVE}&quot; -o &quot;\${ARCHIVE}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          HASH=$(shasum -a 256 &quot;\${ARCHIVE}&quot; | awk &#39;{print $1}&#39;)</span></span>
<span class="line"><span style="color:#A6E3A1;">          echo &quot;\${target}_hash=\${HASH}&quot; &gt;&gt; &quot;$GITHUB_ENV&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          echo &quot;\${target}: \${HASH}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        done</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">        echo &quot;version=\${VERSION}&quot; &gt;&gt; &quot;$GITHUB_ENV&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Update formula</span></span>
<span class="line"><span style="color:#89B4FA;">      run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">        cd homebrew-tap</span></span>
<span class="line"><span style="color:#A6E3A1;">        # Use sed or a templating tool to update version and hashes</span></span>
<span class="line"><span style="color:#A6E3A1;">        # in Formula/my-agent.rb</span></span>
<span class="line"><span style="color:#A6E3A1;">        python3 scripts/update-formula.py \\</span></span>
<span class="line"><span style="color:#A6E3A1;">          --version &quot;\${{ env.version }}&quot; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">          --aarch64-darwin &quot;\${{ env.aarch64-apple-darwin_hash }}&quot; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">          --x86-64-darwin &quot;\${{ env.x86_64-apple-darwin_hash }}&quot; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">          --aarch64-linux &quot;\${{ env.aarch64-unknown-linux-musl_hash }}&quot; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">          --x86-64-linux &quot;\${{ env.x86_64-unknown-linux-musl_hash }}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Commit and push</span></span>
<span class="line"><span style="color:#89B4FA;">      run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">        cd homebrew-tap</span></span>
<span class="line"><span style="color:#A6E3A1;">        git config user.name &quot;github-actions[bot]&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        git config user.email &quot;github-actions[bot]@users.noreply.github.com&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        git add Formula/my-agent.rb</span></span>
<span class="line"><span style="color:#A6E3A1;">        git commit -m &quot;my-agent \${{ env.version }}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        git push</span></span></code></pre></div><p>Alternatively, the <a href="https://github.com/Justintime50/homebrew-releaser" target="_blank" rel="noreferrer"><code>homebrew-releaser</code></a> action handles all of this with less custom scripting.</p><h2 id="testing-your-formula" tabindex="-1">Testing Your Formula <a class="header-anchor" href="#testing-your-formula" aria-label="Permalink to &quot;Testing Your Formula&quot;">​</a></h2><p>Before pushing to users, test the formula locally:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Add your tap</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> tap</span><span style="color:#A6E3A1;"> yourname/tap</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install from the tap</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> yourname/tap/my-agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify the installation</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">my-agent</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run the formula&#39;s test block</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> test</span><span style="color:#A6E3A1;"> my-agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check for formula issues</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> audit</span><span style="color:#A6E3A1;"> --strict</span><span style="color:#A6E3A1;"> --new</span><span style="color:#A6E3A1;"> Formula/my-agent.rb</span></span></code></pre></div><p>The <code>brew audit</code> command checks for common formula problems: missing descriptions, incorrect URLs, style violations, and more. Fix any issues it reports before publishing.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Many Rust CLI tools distribute through Homebrew taps. The pattern is well-established: a release workflow builds binaries, uploads them to GitHub Releases, then updates the tap formula with new URLs and hashes. Tools like <code>cargo-dist</code> and <code>cargo-release</code> can automate the entire pipeline including tap updates, making it a one-command release process.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>A Homebrew tap is a GitHub repository named <code>homebrew-tap</code> containing Ruby formula files in a <code>Formula/</code> directory.</li><li>Formulas for Rust binaries are simple: they download a prebuilt archive, verify its SHA256 hash, and copy the binary into place.</li><li>Use <code>on_macos</code>/<code>on_linux</code> and <code>on_arm</code>/<code>on_intel</code> blocks to serve the correct binary for each platform and architecture.</li><li>Include shell completions (bash, zsh, fish) and man pages in your release archive so the formula can install them alongside the binary.</li><li>Automate formula updates in your release CI pipeline so every new tag automatically updates the tap repository with new version numbers and hashes.</li></ul>`,40)])])}const m=a(e,[["render",t]]);export{d as __pageData,m as default};
